using BogDb.Core.Processor.Operator;

namespace BogDb.Core.Processor.Operator.Result;

/// <summary>
/// The Terminal Sink inside a generic Query processor.
/// Exhausts all recursive GetNextTuple() calls aggregating them into
/// the `QueryResult` memory tables passed back to the Fluent API bindings.
/// </summary>
public sealed class ResultCollector : PhysicalOperator
{
    public uint TuplesCollected { get; private set; }
    public List<object[]> Rows { get; }
    public double? ProfileMilliseconds { get; private set; }

    /// <summary>Output column alias names in projection order (parallel to row values).</summary>
    public IReadOnlyList<string> ColumnNames { get; }

    public ResultCollector(PhysicalOperator child, uint id)
        : this(child, id, System.Array.Empty<string>()) { }

    public ResultCollector(PhysicalOperator child, uint id, IReadOnlyList<string> columnNames)
        : base(PhysicalOperatorType.RESULT_COLLECTOR, child, id)
    {
        TuplesCollected = 0;
        Rows = new List<object[]>();
        ColumnNames = columnNames;
    }

    /// <summary>
    /// Repeatedly pull from the child until completely exhausted.
    /// Represents the entry point to query execution triggers natively.
    /// </summary>
    public override bool GetNextTuple(ExecutionContext context)
    {
        while (Children[0].GetNextTuple(context))
        {
            TuplesCollected++;
            if (context.CurrentProjectionRow != null)
            {
                Rows.Add(context.CurrentProjectionRow);
            }
            else if (context.CurrentNodeProperties != null)
            {
                Rows.Add(new object[] { context.CurrentNodeProperties });
            }
        }

        if (context.CurrentScalarBindings != null &&
            context.CurrentScalarBindings.TryGetValue("__profile_ms", out var profileMs) &&
            profileMs is not null)
        {
            ProfileMilliseconds = System.Convert.ToDouble(profileMs);
        }

        // Technically the ResultCollector is a Sink, it doesn't emit data further up.
        return false; 
    }

    public override bool IsSink() => true;
}
